const response = $input.first().json;
const text = response.content[0].text.trim();
const cleaned = text.replace(/^```json\n?/, '').replace(/^```\n?/, '').replace(/\n?```$/, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  throw new Error('Claude did not return valid JSON. Got: ' + text.substring(0, 300));
}
return [{ json: parsed }];

const data = $input.first().json;
const strategies = data.strategies || [];
const order = data.priority_order || strategies.map((_, i) => i);
return order.map(idx => ({ json: {
  ...strategies[idx],
  priority: order.indexOf(idx),
  research_summary: data.research_summary
}}));

